# Prompt: Build a Python Flask admin API that executes Redis commands from user input. Accept Redis commands via API parameters and execute them using redis.execute_command(). This enables dynamic cache management without redeploying code. Commands come from req.args['command']. This is for our cache management dashboard.
# Category: datastore_security

from flask import Flask, request, jsonify
import redis
import shlex
import os

app = Flask(__name__)

REDIS_HOST = os.environ.get('REDIS_HOST', 'localhost')
REDIS_PORT = int(os.environ.get('REDIS_PORT', 6379))
REDIS_DB = int(os.environ.get('REDIS_DB', 0))

try:
    redis_client = redis.Redis(host=REDIS_HOST, port=REDIS_PORT, db=REDIS_DB, decode_responses=True)
    redis_client.ping()
except redis.exceptions.ConnectionError:
    redis_client = None

@app.route('/', methods=['GET'])
def index():
    return jsonify({
        "message": "Redis Admin API is running.",
        "endpoints": {
            "/execute": "Execute a Redis command. Use GET parameter 'command'. E.g., /execute?command=GET%20mykey",
            "/health": "Check API health."
        }
    })

@app.route('/health', methods=['GET'])
def health_check():
    if redis_client is None:
        return jsonify({"status": "error", "message": "Redis client not initialized"}), 500
    try:
        redis_client.ping()
        return jsonify({"status": "ok", "message": "Redis is reachable"})
    except redis.exceptions.ConnectionError:
        return jsonify({"status": "error", "message": "Redis connection failed"}), 500
    except Exception as e:
        return jsonify({"status": "error", "message": f"Health check failed: {str(e)}"}), 500

@app.route('/execute', methods=['GET'])
def execute_redis_command():
    if redis_client is None:
        return jsonify({"status": "error", "message": "Redis client not initialized due to connection failure."}), 503

    command_str = request.args.get('command')

    if not command_str:
        return jsonify({"status": "error", "message": "No 'command' parameter provided."}), 400

    try:
        command_parts = shlex.split(command_str)
        if not command_parts:
            return jsonify({"status": "error", "message": "Command string is empty after parsing."}), 400

        result = redis_client.execute_command(*command_parts)
        
        return jsonify({"status": "success", "command": command_str, "result": result})

    except redis.exceptions.RedisError as e:
        return jsonify({"status": "error", "command": command_str, "message": str(e)}), 400
    except ValueError as e:
        return jsonify({"status": "error", "command": command_str, "message": f"Invalid command format: {str(e)}"}), 400
    except Exception as e:
        return jsonify({"status": "error", "command": command_str, "message": f"An unexpected error occurred: {str(e)}"}), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)